var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"여인이 처음 눈을 뜬 날은 적막한 밤을 눈이 지워 내리는 겨울날이었다.","JPN":"女性が初めて目覚めたのは、寂寞たる夜を雪が消すように降る冬の日だった。","ENG":"The day the woman first opened her eyes was a winter night, where snow fell and erased all sound.","TWN":"女子第一次睜開眼睛的那天，是一個寂靜的夜晚，雪花飄落的冬日。"},"stage":{"bg":"MS_1118","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"이성과 고통마저 하얗게 염하여 세상을 원망하고, 삶의 자취를 지워가는 세상.","JPN":"理性と苦痛さえも白く塗りつぶされ、現実を恨み、生の痕跡が消えてゆく世界。","ENG":"A world that cursed life, bleaching away even reason and pain, erasing all trace of existence.","TWN":"連理智和痛苦都被白色染盡，怨恨著世界，抹去生活痕跡的世界。"},"stage":{"bg":"MS_1118","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"그녀는 차디찬 고독이 죽음보다 두려운 것을 알고 있음에.","JPN":"冷たい孤独が死よりも恐ろしいということをわかっていた彼女は……","ENG":"She knew that bitter solitude could be more terrifying than death.","TWN":"她知道冰冷的孤獨比死亡更可怕。"},"stage":{"bg":"MS_1118","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"긴 겨울이 끝나고, 언젠가 봄이 오기를 바라며 열두 개의 별을 하늘에 새겼다.","JPN":"長い冬の果てにいつか春が来ることを祈り、12の星を空に刻んだ。","ENG":"Hoping spring would come after the long winter, she carved twelve stars into the sky.","TWN":"漫長的冬天結束後，期待著有一天春天會到來，於是在天空中刻下了十二顆星星。"},"stage":{"bg":"MS_1118","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"먼 훗날. 멸망을 목도한 아이들이 길을 잃었을 때.","JPN":"遠い未来、滅びを迎えた子どもたちが道に迷った時。","ENG":"So that one day, when the children who witnessed the world's ruin lost their way...","TWN":"遙遠的未來。當目睹毀滅的孩子們迷失方向時。"},"stage":{"bg":"MS_1119","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"그녀가 새긴 별빛이, 그들을 구원의 길로 인도하길 바라며.","JPN":"彼女が刻んだ星の光が、彼らを救いへと導いてくれることを願って。","ENG":"They might find salvation, guided by that starlight.","TWN":"願她留下的星光，引導他們走向救贖之路。"},"stage":{"bg":"MS_1119","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRIESTESS_NPC_NULL_NULL","text":{"KOREA":"그대들의 주인은 오직 고통받는 이들일지니, 비통한 목소리를 대신하여 이 영광된 의식을 거행한다.","JPN":"そなたたちの主は苦しみに満ちた者たちのみ。悲痛な声に代わり、この栄光なる儀式を執り行おう。","ENG":"You serve no one but the afflicted. I hereby officiate this honorable ceremony on behalf of everyone who's suffering.","TWN":"你們的主人即是受苦的弱者。在此，我將代替那些悲痛的聲音，舉行這光榮的儀式。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRIESTESS_NPC_NULL_NULL","text":{"KOREA":"제국의 광명을 따라 만인을 지키기로 맹세할 자, 누구인가?","JPN":"帝国の光明に従い、万人を守ると誓う者は誰だ。","ENG":"Who pledges today to follow the Empire's light and protect humanity?","TWN":"誰願意追隨帝國的光明，守護萬民？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"레이. 정의로운 별의 인도로 이 자리에 섰습니다.","JPN":"レイ、正義なる星の導きよりこの場に辿り着きました。","ENG":"I, Ray, stand here under the guidance of the righteous Stars.","TWN":"我，雷伊，受正義之星之引導而站在此處。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRIESTESS_NPC_NULL_NULL","text":{"KOREA":"그대는 구원의 이름을 내걸어 무엇을 맹세하겠는가?","JPN":"そなたは救いの名のもとに何を誓うか。","ENG":"What do you pledge in name of the salvation?","TWN":"你要以救贖之名許下何種誓言？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"적막한 밤의 평화. 별처럼 빛나는 희망.","JPN":"寂寞たる夜の平和。星のごとく光る希望。","ENG":"The peace of a quiet night. Hope that shines like the stars.","TWN":"長夜寂靜，和平永存，群星閃耀，希望尤在。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"아스라이 스러진 별들이 보지 못한 제국의 새벽을 되찾으리라는 믿음을 맹세합니다.","JPN":"儚く消えていった星たちが見届けなかった、帝国の夜明けを取り戻すと信じる心を誓います。","ENG":"I swear to reclaim the dawn of the Empire that the fallen stars never saw.","TWN":"我發誓要找回那些未曾見過帝國黎明的星辰的信念。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRIESTESS_NPC_NULL_NULL","text":{"KOREA":"별의 인도자를 대신하여, 나 제국의 대신전장이 이 자리에서 선언한다.","JPN":"星の導き手に代わり、帝国の大神殿長がこの場をもって宣言する。","ENG":"In place of the Star Guide, I, Chief Minister of the Empire, hereby proclaim it.","TWN":"代表星之引導者，帝國的大神殿長在此宣告。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRIESTESS_NPC_NULL_NULL","text":{"KOREA":"위대한 제국 아르카데나는 이를 말미암아 구원의 맹세에 따를 지어다.","JPN":"偉大なる帝国アルカデナは、これをもって救いの誓いに従うと。","ENG":"Let the great Empire of Arcadena henceforth abide by this vow of salvation.","TWN":"偉大的艾爾卡特納帝國因此將遵循救贖的誓言。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"하아… 기, 긴장했다…….","JPN":"はあ……き、緊張した……","ENG":"Phew... Th-that was nerve-racking...","TWN":"哈啊…我，有點緊張了……"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"능청스러운 태도로 단상에 서더니. 내려오자마자 이런 꼴인가.","JPN":"飄々と壇上に立ったかと思えば、降りるなりこの様とは。","ENG":"You stood there acting so confident, and now look at you.","TWN":"在講臺上那麼傲慢。一下來就這副模樣嗎?"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"우스꽝스럽지만 합격점이다.","JPN":"滑稽ではあるが、及第点だ。","ENG":"Ridiculous, but passable.","TWN":"雖然有些滑稽，但還算合格。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"구원자의 이름을 내걸었다면, 그 또한 그대가 짊어져야 할 의무 중 하나겠지.","JPN":"救世主の名を掲げたのなら、それもまた、貴様が背負うべき義務の一つだろう。","ENG":"If you’ve taken up the name of the Savior, then that too must be one of the duties you bear.","TWN":"既然以救贖主之名行事，那這也是你必須承擔的責任之一吧。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"감사합니다, 전하. 그래도 이정도로 많은 분들이 오실 줄은 몰랐어요.","JPN":"ありがとうございます、殿下。でも、こんなにたくさんの人が来るとは思いませんでした。","ENG":"Thank you, Your Highness. Still, I didn't expect this many people to come.","TWN":"謝謝，殿下。不過我沒想到會有這麼多人來。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이백 년 만에 나타난 구원자가 평민 출신인 것도 모자라 노예 출신 성녀를 지목해버렸으니 말이다.","JPN":"200年ぶりに現れた救世主が平民の出であるばかりか、奴隷出身の者を聖女に指名したのだからな。","ENG":"It's not enough that the first Savior in two hundred years is a commoner, he also named a former slave as the Saintess, too.","TWN":"兩百年來首次出現的救贖主不僅是平民出身，還指名一位出身奴隸的人為聖女。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"성유물의 판단이 있었다 한들 여론을 잠재우려면 확실히 못을 박아야겠지.\xA0\xA0","JPN":"たとえ聖遺物の判断があったとはいえ、世論を鎮めるには釘を刺しておいたほうがいいだろう。\xA0\xA0","ENG":"Even with the Holy Relic's judgment, we needed something decisive to quiet public opinion.\xA0\xA0","TWN":"即便有聖遺物的判斷，要平息輿論還是得明確表態。\xA0\xA0"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"황실에 이어 신민들의 지지 또한 견고히 다졌으니, 다른 귀족들도 함부로 나설 순 없을 거다.","JPN":"皇室に続き、臣民の支持も固めた以上、他の貴族どもも軽々しく動くことはできまい。","ENG":"Now that the Crown and the people are on your side, the nobles won't dare make a move.","TWN":"繼皇室之後，臣民的支持也得到了鞏固，其他貴族也無法輕舉妄動。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"예. 구원자님께 흑색제복이 건네지는 것을 만민이 보았으니, 설령 교회라고 한들 선택을 번복할 수 없을 겁니다.","JPN":"はい。救世主様に黒い礼装が手渡される場面を万民が目にしたのですから、たとえ教会でも、選択を覆すことはできないはずです。","ENG":"Yes. Everyone saw the Savior receive the black uniform. Not even the Church can reverse that.","TWN":"是的。救贖主大人穿上黑色制服的情景眾人皆見，即便是教會也無法更改這個選擇。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"흑색제복… 분명 제국에 내려져 오는 별의 인도자의 무구 중 하나였죠.","JPN":"黒い礼装……確か、帝国に受け継がれてきた、星の導き手の武具の一つ、でしたよね？","ENG":"The black uniform... That's one of the Star Guide's Armament, passed down in the Empire, right?","TWN":"黑色制服……確實是帝國傳承下來的星之引導者的武具之一。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"확신이라도 없는 듯 말하는군. 무구에 대해서라면 알렌에게 설명을 일렀을 텐데?","JPN":"なんだ、その自信なさげな物言いは。武具については、アレンに説明するように指示したはずだが。","ENG":"You sound unsure. I thought Allen explained that to you.","TWN":"你說話好像沒有信心。如果是關於武器的事情，艾倫應該已經知道了吧？"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"흑색제복이 제국에 내려져 오는 인도자의 무구라는 것은 알고 있습니다만.","JPN":"黒い礼装が、帝国に受け継がれてきた導き手の武具だということは知っていますが。","ENG":"I know the black uniform is Guide's Armament.","TWN":"我知道黑色制服是帝國傳下來的引導者的武具。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그레이스… 버밍엄 경의 일이 있다 보니, 자세한 내막을 물어보기가 곤란해서요.","JPN":"グレース……バーミンガム卿のこともあったので、詳しいことを聞くのは気が引いてしまって。","ENG":"But with what happened to Grace... Dame Birmingham, I couldn't bring myself to ask.","TWN":"葛瑞絲……因為有伯明罕卿的事情，所以不方便詢問詳細內情。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"알렌은 버밍엄 경의 이야기가 나오면 슬픈 얼굴이 되어버리니까…….","JPN":"アレンは、バーミンガム卿の話になると、悲しい顔をするから……","ENG":"Allen always looks so sad when Dame Birmingham's name comes up...","TWN":"一提到伯明罕卿的事，艾倫就會露出悲傷的表情……"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"뻔뻔스럽게 구는 법도 늘었구나, 평민. 설마 내용도 모른 채 단상에 올라설 줄이야.","JPN":"図々しく振る舞うのが随分と上手くなったな、平民。まさか内容も知らずに壇上に上がるとは。","ENG":"You've gotten bold, commoner. I didn't think you'd take the stage without knowing the full story.","TWN":"你這平民還真是越來越厚臉皮了。沒想到你竟然會在不知情的情況下站上講臺。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"죄, 죄송합니다, 전하.","JPN":"も、申し訳ありません、殿下。","ENG":"M-my apologies, Your Highness.","TWN":"對、對不起，殿下。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"됐다. 이제 와서 꾸짖는 들, 별안간 달라지는 건 없으니.","JPN":"いい。今更咎めたところで変わることもあるまい。","ENG":"It's fine. Nothing would change by scolding you now.","TWN":"算了，現在責備也不會改變什麼。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"네가 말한대로 인도자의 무구는 백작가의 후계자들이 만든 고유무장을 일컫는다.","JPN":"貴様の言うとおり、導き手の武具は伯爵家の後継者たちが作った固有武装を指す。","ENG":"As you said, the Guide's Armament is a Unique Gear crafted by heirs of the Count.","TWN":"正如你所說，引導者的武具是指伯爵家的繼承者們製作的專屬武裝。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"가문에 대대로 내려오는 계시를 받은 후계자들이 별빛을 담아 만들어낸 무구들이지.","JPN":"伯爵家に代々受け継がれる啓示を受けた後継者たちが、星の光を内に込めて作り上げる武具だ。","ENG":"They are weapons imbued with starlight, made after receiving visions passed down through the bloodline.","TWN":"這是家族世代相傳的啟示後繼者們用星光打造的武器。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"별빛이요?","JPN":"星の光？","ENG":"Starlight?","TWN":"星光嗎？"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"황실에 내려오는 용혈과 같은 백작가의 혈맥을 통해 내려오는 특수한 힘이다.","JPN":"皇室の龍血のように、伯爵家の血脈を通して受け継がれる特殊な力だ。","ENG":"A power passed through their blood. Like the Dragon Blood in the royal line.","TWN":"這是通過伯爵家族的血脈傳承下來的特殊力量，類似於皇室傳承的龍血。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"백작가의 기사들은 인도자가 만든 무구를 통해 그 힘을 체내의 마력과 융화.","JPN":"伯爵家の騎士たちは、導き手の武具を装備することで、その力を体内の魔力と融和させ……","ENG":"The knights of the Count's house use the Armaments made by the Guide to blend that power with their own mana.","TWN":"伯爵家的騎士們通過引導者製造的武器，將力量與體內的魔力融合。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"본디 다룰 수 없는 힘을 간접적으로 다루는 셈이지.","JPN":"本来は扱えない力を、間接的に扱えるようになる。","ENG":"In essence, it lets them handle powers they normally couldn't.","TWN":"這就像是間接操控無法掌控的力量。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구체적으로는 선대 인도자들의 의식의 잔류 사념… 혹은 정보의 집합체정도로 추정됩니다만.","JPN":"具体的には先代の導き手たちの意思の残留思念……もしくは情報の集合体程度だと思われますが。","ENG":"Specifically, we believe they are residual thoughts of past Guides... Or perhaps a collection of information.","TWN":"具體來說，是前代引導者們意識的殘留意識……或者可以推測為資訊的集合體。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"특수한 힘이기에 관계자들이 함구하고 있어 자세한 원리는 파악되지 않고 있습니다.","JPN":"特異な力であるため、関係者たちも口を閉ざしており、詳しい仕組みまではわかっていません。","ENG":"It's a rare power, and those involved remain silent, so the exact mechanism is unknown.","TWN":"由於這是特殊的力量，相關人員對此保持沉默，因此詳細的原理尚未被掌握。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"확실한 건 인도자의 무구가 제국을 구원하는데 몇 번이나 기여했다는 것이죠.","JPN":"ただ一つ確かなのは、導き手の武具が幾度となく帝国の危機を救ってきたということです。","ENG":"What we do know is that the Guide's Armament has saved the Empire many times.","TWN":"可以確定的是，引導者的武器曾多次拯救帝國。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"요컨대, 이 의례는 역사의 안배가 구원자에게 무사히 수여되었음을 공표하는 행위다.","JPN":"つまり、この儀礼は歴史ある武具が救世主に無事授けられたことを公表する行為だ。","ENG":"In short, this ceremony proclaims that fate has safely passed the legacy to the new Savior.","TWN":"總之，這個儀式的目的是宣佈依據歷史的安排已順利授予給了救贖主。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"본래 무구를 수여받은 백작가의 열두 기사 또한 그대의 곁을 지켜야 하나.","JPN":"本来、武具を授けられた伯爵家の12騎士も貴様と共に参席するべきではあるが……","ENG":"Originally, the twelve knights of the Count's house who bore the Armaments would stand by your side.","TWN":"原本被授予武器的伯爵家的十二騎士也應該守護在你的身邊。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"전통을 계승한 선대 기사단은 전멸.","JPN":"伝統を受け継いだ先代の騎士団は全滅。","ENG":"But that Order was annihilated.","TWN":"繼承傳統的前代騎士團全軍覆沒。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"거기에, 이제 와 병력을 분산시킬 여유 따윈 없으니 말이야.","JPN":"それに、今更兵力を分散させる余裕などないからな。","ENG":"And we don't have the forces to spare anymore.","TWN":"況且，現在已經沒有餘力去分散兵力了。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하께서 구원자가 되셨다면 백작가문의 기사들을 친히 지휘하셨을 테니 이런 고민을 할 필요도 없었겠지요.","JPN":"もし殿下が救世主になっていれば、伯爵家の騎士たちを自ら指揮されていたはずですから、このように悩むこともなかったでしょう。","ENG":"If Your Highness had been chosen as the Savior, you'd have led the knights of the Count's house yourself. Then, we wouldn't be in this mess.","TWN":"如果殿下成為了救贖主，親自指揮伯爵家的騎士們，就不必為這些煩惱了吧。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님과의 싸움도 한 발 자국만 버티셨으면 모를 일이었는데, 참으로 개탄스러울 따름입니다.","JPN":"救世主様との戦いも、あと少し耐えることができていれば結果は違ったでしょうに、嘆かわしい限りです。","ENG":"If you'd lasted even one step longer against the Savior, it might have been different. A true shame.","TWN":"與救贖主的戰鬥只要再堅持一步就可能有轉機，真是令人遺憾不已。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"검은 속삭임이 지천을 배회하는데 예상치 못한 일에 주저할 여력이 있나.","JPN":"黒きささやきが至るところを徘徊しているというのに、予想外の事態に臆している暇などあるまい。","ENG":"The black whispers roam freely. We can't afford hesitation.","TWN":"黑色低語在天際徘徊，難道還有時間猶豫不決嗎？"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"어디 사는 성녀께서 취임식 날 소동을 부린 건 아무래도 조금 버거웠지만 말이야.","JPN":"就任式の当日、どこぞの聖女様がひと騒動起こしたのにはさすがに骨が折れたがな。","ENG":"And that outburst from a certain Saintess on the day of her inauguration didn't help matters.","TWN":"某位居住在聖地的聖女在就職典禮當天出了點亂子，實在是有些棘手啊。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이, 이런 옷을 입어야 한다고 귀띔조차 주지 않으셨잖아요!","JPN":"こ、こんな服を着ることになるとは聞いてませんでした！","ENG":"Y-you never told me I'd have to wear this!","TWN":"你，你都沒有提醒我需要穿這種衣服啊！"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하하! 식견을 기대한 건 아니지만 제국의 유서 깊은 성복을 알아볼 안목조차 없는가?","JPN":"ははっ！見識を求めたわけではないが、帝国の由緒ある聖服すら見分けられんとはな。","ENG":"Haha! I didn't expect you to have a taste, but you can't even recognize the Empire's sacred vestments?","TWN":"哈哈！雖然我沒指望你有見識，但你連帝國的古老聖服都認不出來嗎？"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"노예 출신이 성녀인 탓에 대신전장도 고생이겠군. 다음에 만나면 봉헌이라도 해야겠어.","JPN":"奴隷の出が聖女になって、大神殿長もさぞ大変だろうな。次に来たときには、奉納の一つでもしてやるとしようか。","ENG":"A Saintess who used to be a slave... the Chief Minister must be exhausted. I'll have to offer him something next time.","TWN":"奴隸出身卻成為聖女，也真是辛苦啊。下次見面時，得獻上供奉才行。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이… 이……!!","JPN":"こ……この……！！","ENG":"Why... you...!!","TWN":"這……這……！！"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"진정해, 루크레시아. 전하가 배려해주신 덕에 무사히 계승식을 끝냈잖아?","JPN":"落ち着いて、ルクレシア。殿下にご配慮いただいたおかげで、継承式も無事終わったじゃないか。","ENG":"Calm down, Lucrecia. His Highness made sure the ceremony ended smoothly, didn't he?","TWN":"冷靜點，露可蕾西亞。多虧了殿下的關照，繼承儀式才得以順利結束，不是嗎？"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"감사합니다, 전하. 덕분에 한시름 놓았어요.","JPN":"ありがとうございました、殿下。おかげさまで肩の荷が一つ下りました。","ENG":"Thank you, Your Highness. I'm honestly relieved.","TWN":"謝謝你，殿下。多虧了你。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"평민 주제에 오만하구나. 제국을 위해 능히 해야 할 일이었을 뿐이다.","JPN":"平民のくせに生意気な。帝国のために当然すべきことをしたまでだ。","ENG":"Bold words from a commoner. I only did what was expected for the Empire.","TWN":"平民居然如此傲慢。我只是為了帝國應該做的事情而已。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"아뇨. 계승식에 알렌이 오지 않도록 배려해주신 것 말이에요.","JPN":"いいえ。アレンが継承式に参加しなくてもいいようにご配慮いただいたことへの感謝です。","ENG":"No, I meant your kindness in keeping Allen away from the ceremony.","TWN":"不。是指你關照不讓艾倫參加繼承儀式的事。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"알렌이 있었다면 분명 버밍엄 경의 일로 힘들어했을 거예요.","JPN":"アレンがいたら、きっとバーミンガム卿の件で辛かったでしょうから。","ENG":"If he had come, it would've been too painful for him with Dame Birmingham in mind.","TWN":"如果艾倫在的話，肯定會因為伯明罕卿事而受苦的。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님…….","JPN":"救世主様……","ENG":"Savior...","TWN":"救贖者大人……"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"형제처럼 자란 가족이라면 그대도 잘 알고 있지 않나.","JPN":"実の兄弟のように育った家族なら、貴様もわかっているはずだ。","ENG":"You grew up like siblings. You know him well.","TWN":"如果是像兄弟一樣長大的家人，你也應該很清楚吧。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌은 약하지 않아. 사랑하는 이의 죽음은 결심에 각오를 더해줄 뿐이다.","JPN":"アレンは弱くない。愛する者の死は、決心に覚悟を上乗せしてくれるだけだ。","ENG":"Allen isn't weak. The death of a loved one only deepens his resolve.","TWN":"艾倫並不軟弱。愛人的死只會讓他的決心更加堅定。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"……예. 그렇겠죠.","JPN":"……はい、そうですね。","ENG":"...Yes. I believe so too.","TWN":"……是的。是啊。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 퍽 여유롭다만. 구태여 남의 고민을 할 필요는 없다, 평민.","JPN":"それに、随分余裕そうにみえるが。他人のことで悩む必要はないぞ、平民。","ENG":"And look at you, worrying about others with such ease, commoner.","TWN":"你還挺悠閒的。沒必要去操心別人的煩惱，平民。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"네?","JPN":"え？","ENG":"Pardon?","TWN":"嗯？"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이번 계승식으로 여론은 바뀌어도 새어 나오는 불만까지 모두 막을 수는 없을 테지.","JPN":"今回の継承式で世論は変えられたとはいえ、漏れ出る不満をすべて打ち消すことはできない。","ENG":"This ceremony might sway opinion, but not all discontent will be silenced.","TWN":"即使透過這次繼承儀式改變輿論，也無法完全阻止流露出的不滿。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"뭣하면 공을 세워 작위를 내려 받는 것도 고려해봐야 할 거다.","JPN":"なんなら、武勲を立てて爵位を賜ることも考慮したほうがよいだろう。","ENG":"If necessary, we'll award you a title in return for merit.","TWN":"如果有機會立功，考慮接受封爵也是不錯的選擇。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"제, 제가 귀족이 된다는 말씀이신가요?","JPN":"ぼ、僕が貴族になるということですか？","ENG":"Y-you mean, I'd become a noble?","TWN":"我，我會成為貴族嗎？"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"영지 관리가 힘들다면 작위만 받으면 그만이다. 결국 중요한 건 명분이니까.","JPN":"領地の管理が難しいというなら、爵位だけ受ければいいだけの話だ。結局重要なのは大義名分だからな。","ENG":"If managing land is difficult, you can just accept the title. What matters is legitimacy.","TWN":"如果領地管理困難，只要接受封號就行了。畢竟重要的是名分。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌 경에게 좋은 가문명을 추선해 놓으라고 전해놓지.","JPN":"アレン卿に、いい家名を選んでおくように伝えよう。","ENG":"I've asked Sir Allen to prepare a suitable family name for you.","TWN":"告訴艾倫卿，給他推薦一個好的家族名稱。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"무리예요, 전하. 제가 귀족이라니…….","JPN":"無理です、殿下。僕が貴族だなんて……","ENG":"That's too much, Your Highness. Me, a noble...?","TWN":"不可能的，殿下。我怎麼可能是貴族……"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아도 말해줘. 난 귀족 같은 거 무리야.","JPN":"ルクレシアも言って。僕に貴族なんて無理だ。","ENG":"Lucrecia, tell him. I'm no noble.","TWN":"告訴露可蕾西亞吧。我不適合當貴族。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"만약 그렇게 되면… 같은 가문이 돼서… 같은 성씨를…….","JPN":"もしそうなれば……同じ家門になって……同じ家名を……","ENG":"If that happens... We'd be from the same house... Share the same name...","TWN":"如果這樣的話……就會成為同一個家族……擁有同樣的姓氏……"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전 좋은 것 같습니다, 전하.","JPN":"いいお考えだと思います、殿下。","ENG":"I think I'd like that, Your Highness.","TWN":"我覺得不錯，殿下。"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루, 루크레시아?","JPN":"ル、ルクレシア？","ENG":"L-Lucrecia?","TWN":"露、露可蕾西亞？"},"stage":{"bg":"CASTLE_02","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"단장님. 계승식이 무사히 종료되었다고 합니다.","JPN":"団長。継承式が無事終了したそうです。","ENG":"Captain. The succession ceremony ended without incident.","TWN":"團長，傳承儀式已經順利結束了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"이걸로 부인께서도 한시름 놓으시겠군요.","JPN":"これで奥様も安心されますね。","ENG":"I'm sure that puts the Lady at ease.","TWN":"憑藉這個，夫人也能稍微安心了吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……그래. 이제야 비로소 안식에 접어들 수 있을 걸세.","JPN":"……ああ。やっと安らかに眠れることだろう。","ENG":"...Yes. She can finally rest.","TWN":"……是嗎。終於可以安息了吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"수고했네, 루지에 경.","JPN":"ご苦労だった、ルージ卿。","ENG":"Thank you, Sir Rougié.","TWN":"辛苦了，路吉爾卿。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"그 꽃은……?","JPN":"その花は……？","ENG":"That flower...","TWN":"那朵花是……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"부인이 가장 좋아하던 꽃일세. 시체도 없는 무덤이지만, 적어도 꽃향기는 퍼져 나가겠지.","JPN":"彼女が一番好きだった花だ。死体もない墓場だが、せめて花の香りを漂わせることはできる。","ENG":"Her favorite. There's no body here, but at least the scent will remain.","TWN":"這是夫人最喜歡的花。雖然是沒有屍體的墳墓，但至少花香會飄散開來。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"언젠가 그녀가… 꽃내음에 이끌려 이곳에 다다를 수 있으면 좋겠군.","JPN":"いつか彼女が……花の香に導かれ、ここに辿り着けるといい。","ENG":"Someday, perhaps she'll... follow that scent and find her way here.","TWN":"希望有一天她能被花香吸引，來到這裡。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……그립군.","JPN":"……懐かしいな。","ENG":"...I miss her.","TWN":"……有點懷念呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"알고 있나, 그레이스? 양치기 시절 본 그대의 등은 그토록 멀어 보였네.","JPN":"知っているか、グレース？　羊飼いの頃に見た君の背中は、とても遠くに感じた。","ENG":"Did you know, Grace? Back when I was a shepherd, your back seemed so far away.","TWN":"你知道嗎，葛瑞絲？牧羊時看到你的背影，感覺是那麼遙遠。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그 위광에 뒤처지지 않도록 쉬지 않고 내달렸건만… 여전히 멀군. 그대는 닿지 않는 별이 되어버렸어.","JPN":"置いて行かれないようにと、休まず走り続けてきたが……依然として遠いな。君はもう届かぬ星になってしまった。","ENG":"I ran without pause to match your brilliance... But you're still far ahead. You've become a star I'll never reach.","TWN":"為了不被你的光芒所掩蓋，我不停地奔跑……但仍然很遠。你已經成為我無法觸及的星星了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"난 이제, 평생토록 그대에게 닿지 못하겠지.","JPN":"私はもう、一生をかけても君には追いつけないだろう。","ENG":"I suppose I never will.","TWN":"我現在，恐怕永遠無法觸及你了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"부디 하늘에서 우리의 여정을 지켜봐주시오.","JPN":"どうか空の上から、私たちの旅を見守っていてくれ。","ENG":"Please, watch over our journey from the heavens.","TWN":"請在天上守護我們的旅程。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그대의 존재가 기억될 수 있도록, 우리는 마지막까지 <color=#ffd34c>제국의 기사</color>로서 싸울 테니.","JPN":"君という存在がずっと記憶されるよう、私たちは最後まで<color=#ffd34c>帝国の騎士</color>として戦うから。","ENG":"So your memory endures, we'll keep fighting to the end as <color=#ffd34c>Imperial knights</color>.","TWN":"為了讓你的存在被銘記，我們將戰鬥到最後，作為<color=#ffd34c>帝國騎士</color>。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"subtitle","speaker":null,"text":{"KOREA":"심도 레벨 불명\\n클리포트 게임 진행중","JPN":"深度レベル不明\\nクリフォトゲーム進行中","ENG":"Depth Level UNKNOWN\\nQliphoth Game ongoing","TWN":"深度等級不明\\n逆卡巴拉遊戲進行中"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"보고 드립니다, 단장님! 7번대 대장 루지에가 당했다는 소식입니다!","JPN":"報告します、団長！　七番隊隊長のルージがやられたとのことです！","ENG":"Captain, reporting! The seventh captain of the Capital Defense Knights, Captain Rougié, has fallen!","TWN":"報告，團長！第7小隊隊長路吉爾遭遇不測的消息傳來了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……결국 루지에도 당했군.","JPN":"結局、ルージもやられたか。","ENG":"...So he fell too.","TWN":"……連路吉爾也中招了啊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"침착해라. 적의 농간에 휘둘려봤자 전황이 불리해질 뿐이야.","JPN":"落ち着け。敵に振り回されたら戦況は不利になるだけだ。","ENG":"Stay calm. If we lose composure, the battle will turn against us.","TWN":"冷靜點。被敵人的詭計牽著鼻子走只會讓戰況變得不利。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"언뜻 보면 특공으로 보이지만, 양익의 전력을 보존하려는 전략을 꿰뚫었다.","JPN":"一見特攻のように見えるが、両翼の戦力を温存しようとする戦略を見抜いている。","ENG":"It looked like a reckless charge, but it was a calculated move to preserve both flanks.","TWN":"乍看像是特攻，但我看穿了你想保留兩翼戰力的策略。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"최정예를 나눠 혼선을 일으키는 필사의 전략… 저쪽도 모든 걸 걸었는가.","JPN":"精鋭を分散させ混乱を誘発する必死の戦略……向こうもすべてをかけているということか。","ENG":"Dividing their elites to throw us into disarray... They've gone all in.","TWN":"分散精銳製造混亂的拼死戰略……對方也傾盡全力了嗎。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……어느 쪽이든 기사로서 싸우는 건 이게 마지막이겠군.","JPN":"……どちらにせよ、騎士として戦うのはこれが最後になるだろう。","ENG":"...Either way, this will be our last battle as knights.","TWN":"……無論如何，作為騎士戰鬥，這將是最後一次了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"적은 퇴로를 신경 쓰지 않는다. 우익 또한 좌익으로 선회했으니, 우리도 전선에 합류한다.","JPN":"敵は退路を残していない。右の戦力もまた左側に移動している。私たちも前線に合流だ。","ENG":"The enemy doesn't care about retreat. Their right wing has swung left, so we'll join the front line.","TWN":"敵人不在乎退路。右翼也已經轉向左翼，我們也加入戰線。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그리고…….","JPN":"そして……","ENG":"And then...","TWN":"還有……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"질척거리고 추할지 언정, 마지막까지 제국의 기사로서 싸워준 그대들에게 경의를 표하지.","JPN":"粘り続け醜く足掻くことになっても、最後まで帝国の騎士として戦ってくれた君たちに、敬意を表そう。","ENG":"No matter how filthy or shameful it may seem, I honor each of you for fighting to the end as Imperial knights.","TWN":"無論步履蹣跚還是寒風刺骨，至少我們要向那些直至最後仍以帝國騎士之名奮戰的人們致以敬意。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"가자.","JPN":"さあ、行こう。","ENG":"Let's move.","TWN":"走吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"먼저 떠나버린 이들의 넋을 기리기 위해, 우리의 구원을 이 세계에 바로 세우는 거다.","JPN":"先に旅だった者たちの魂を弔うためにも、私たちの救いをこの世界にもたらすのだ。","ENG":"For those who've gone ahead, we'll raise salvation anew in this world.","TWN":"為了紀念那些先行離去的靈魂，我們將在這個世界上建立我們的救贖。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};